      const k = parseInt(c, 10);
      count[k] = (count[k] || 0) + 1;
    }
    for (const [key in count]) {
      if (count[key] !== parseInt(key, 10)) {
        return false;
      }
    }
    return true;
  }

  // Generate next possible special number
  function nextSpecial(n) {
    let i = n + 1;
    while (true) {
      if (isPalindrome(i) && isSpecial(i)) {
        return i;
      }
      i++;
    }
  }

  return nextSpecial(n);
